output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?conflict ?conflictLabel ?start WHERE {
  ?conflict wdt:P31 wd:Q1985100 ; wdt:P4745 wd:Q96 ; wdt:P580 ?start .
  OPTIONAL {
    ?conflict rdfs:label ?conflictLabel
    FILTER(LANG(?conflictLabel) = "en")
    .
  }
  FILTER(YEAR(?start) >= 1601 && YEAR(?start) <= 2100)
}
ORDER BY ASC(?start)

args.sparql:
SELECT DISTINCT ?conflict ?conflictLabel WHERE { ?conflict wdt:P31 wd:Q1985100; # instance of military conflict
  wdt:P571 ?start;
  wdt:P710 wd:Q96. # Mexico as participant
  OPTIONAL { ?conflict rdfs:label ?conflictLabel FILTER(LANG(?conflictLabel) = "en"). }
  FILTER(year(?start) >= 1601 && year(?start) <= 2100)
} ORDER BY ASC(?start) LIMIT 20

SELECT ?conflict ?conflictLabel ?start WHERE { 
  ?conflict wdt:P31 wd:Q1985100; # instance of military conflict
         wdt:P4745 wd:Q96; # aggressor is Mexico
         wdt:P580 ?start .
  OPTIONAL { ?conflict rdfs:label ?conflictLabel FILTER(LANG(?conflictLabel) = "en"). }
